code.C:
#include <stdio.h>
int main() {
    int T, X, Y;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        scanf("%d %d", &X, &Y);
        printf("%d\n", X - Y);
    }
    return 0;
}

